    click() {
        const anchor = this.emailAnchor;
        if (anchor && anchor.click) {
            anchor.click();
        }
    }
    get emailAnchor() {
        if (this._connected && this.hasValue) {
            return this.template.querySelector('a');
        }
        return undefined;
    }
